// Brands whose official color is near-black: on dark surfaces they vanish,
// so they follow the theme foreground color instead.
const DARK_BRANDS = new Set(["x", "tiktok"]);

export function BrandIcon({ slug, className, monochrome = false, ...props }) {
  const brand = BRANDS[slug];
  if (!brand) return null;
  const adaptive = !monochrome && DARK_BRANDS.has(slug);
  return (
    <svg
      viewBox="0 0 24 24"
      className={cn(adaptive && "text-foreground", className)}
      fill={monochrome || adaptive ? "currentColor" : brand.color}
      aria-hidden="true"
      {...props}
    >
      <path d={brand.path} />
    </svg>
  );
}

export const brandColor = (slug) => BRANDS[slug]?.color || "#666";
